INSERT INTO seasonal_tips (month, category, title, content) VALUES
(5, 'Teknik', 'Su Deposu Temizliği', 'Yaz sezonu başlamadan önce su depolarınızı gümüş iyonlu tabletlerle dezenfekte etmeyi unutmayın.'),
(5, 'Rota', 'Batı Karadeniz Zamanı', 'Mayıs ayı, Batı Karadeniz ormanlarının en yeşil olduğu dönemdir. Yedigöller ve Akçakoca rotalarını değerlendirin.'),
(5, 'Ekipman', 'Sineklik Kontrolü', 'Havaların ısınmasıyla artan haşerelere karşı tüm sinekliklerinizi kontrol edin, yırtık varsa onarın.'),
(6, 'Enerji', 'Panel Isınması', 'Paneller çok ısındığında verim düşer. Panellerin altındaki hava boşluğunun açık olduğundan emin olun.'),
(6, 'Kamp', 'Gölge Stratejisi', 'Yazın konaklarken karavanın kapısının kuzeye bakması, tentenizin gün boyu gölge sağlamasına yardımcı olur.'),
(12, 'Isınma', 'Webasto Bakımı', 'Kışın ortasında kalmamak için dizel ısıtıcınızın yakıt filtresini ve egzoz çıkışını temizleyin.'),
(1, 'Donma', 'Grit Su Tahliyesi', 'Don riski olan bölgelerde gri su vananızı açık bırakın veya uygun bir antifriz kullanın.');
